/****
 * CALC to return =CQP_TOTAL_FORTE_SHARE * CQP_STORAGE_EEL
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

return safeNumber((this._parent.CQP_TOTAL_FORTE_SHARE/100)) * safeNumber(this.CQP_STORAGE_EEL);

/****
 * CALC to return =((CQP_STORAGE_EEL/CQP_HISTORICAL_EEL)-1)*100
 * By Adriana Centellas
 * Edited By Natalia Mendez
 */

// Convert any value to a safe number
function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

// Ensure numeric values
let storageEEL = safeNumber(this.CQP_STORAGE_EEL);
let historicalEEL = safeNumber(this.CQP_HISTORICAL_EEL);

// Main calculation
var returnVar = (historicalEEL !== 0 && storageEEL !== 0)
  ? ((storageEEL / historicalEEL) - 1) * 100
  : 0;


// Remove classes first
setTimeout(function () {
  const inputSelector = $('[selector="CQP_VARIATION_EEL"] > div > input');
  inputSelector.removeClass('inputError inputOk');
}, 200);


// Only evaluate color if result is a valid number and not zero
if (!Number.isNaN(returnVar) && returnVar !== 0) {

  let valor = parseFloat(returnVar);

  setTimeout(function () {
    const inputSelector = $('[selector="CQP_VARIATION_EEL"] > div > input');
    inputSelector.removeClass('inputError inputOk');

    if (valor < 0) {
      inputSelector.addClass('inputError'); // red
    } else if (valor > 0) {
      inputSelector.addClass('inputOk'); // green
    }

  }, 500);
}

return returnVar;

